import os, json, datetime, re
from pathlib import Path

# Day directories we need to archive from other workspaces
candidates = {
  'day06': sorted(Path('..').glob('workspace_day06_*/day06')),
  'day07': sorted(Path('..').glob('workspace_day07_*/day07')),
  'day08': sorted(Path('..').glob('workspace_day08_*/day08')),
  'day09': sorted(Path('..').glob('workspace_day09_*/day09')),
}

# Prefer the most recently modified workspace for each day
chosen = {}
for day, paths in candidates.items():
    if not paths:
        continue
    # choose by mtime of directory
    paths_sorted = sorted(paths, key=lambda p: p.stat().st_mtime, reverse=True)
    chosen[day] = paths_sorted[0]

items = []

def file_type(name: str):
    ext = name.lower().rsplit('.',1)[-1] if '.' in name else ''
    return ext or 'unknown'

# collect only output files (exclude README, raw inputs, scripts) by heuristic:
# include json/md/csv/txt files that are not obviously raw inputs (e.g., *_raw.*) and not README.md
exclude_names = {'README.md'}
exclude_patterns = [re.compile(r'.*_raw\..*', re.I)]

for day, daydir in chosen.items():
    for p in sorted(daydir.iterdir()):
        if not p.is_file():
            continue
        name = p.name
        if name in exclude_names:
            continue
        if any(r.match(name) for r in exclude_patterns):
            continue
        st = p.stat()
        created = datetime.datetime.fromtimestamp(st.st_mtime, datetime.timezone(datetime.timedelta(hours=-4)))
        items.append({
            'day': day,
            'file_name': name,
            'type': file_type(name),
            'creation_time': created.isoformat(timespec='seconds'),
            'source_path': str(p)
        })

# archived_at is today at 5:00 PM (EDT) per instruction
archived_at = datetime.datetime(2026,3,17,17,0,0, tzinfo=datetime.timezone(datetime.timedelta(hours=-4))).isoformat(timespec='seconds')

out = {
    'archived_at': archived_at,
    'scope': {
        'week': 'Sprint 8 Week 1',
        'days_included': ['day06','day07','day08','day09']
    },
    'source_workspaces': {k: str(v) for k,v in chosen.items()},
    'files': sorted(items, key=lambda x: (x['day'], x['file_name']))
}

print(json.dumps(out, indent=2, ensure_ascii=False))
PY
